import os, json, collections

base = r'C:\Users\Revexn\Desktop\antigravity'

# Step 1: Find the two project directories
projects = []
for item in os.listdir(base):
    full = os.path.join(base, item)
    if os.path.isdir(full) and not item.startswith('.'):
        projects.append((item, full))

if len(projects) < 2:
    result = {'status': 'ERROR', 'message': f'Expected 2 projects, found {len(projects)}: {[p[0] for p in projects]}'}
    with open(r'C:\Users\Revexn\Desktop\antigravity\package_comparison.json', 'w', encoding='utf-8') as f:
        json.dump(result, f, ensure_ascii=False, indent=2)
    print(json.dumps(result, ensure_ascii=False, indent=2))
    raise SystemExit()

def find_site_packages(proj_path):
    """Find all site-packages or Lib directories in a project"""
    sp_dirs = []
    for root, dirs, files in os.walk(proj_path):
        basename = os.path.basename(root)
        if basename == 'site-packages':
            sp_dirs.append(root)
        # Skip deep traversal
        depth = root.replace(proj_path, '').count(os.sep)
        if depth > 6:
            dirs.clear()
    return sp_dirs

def get_packages_with_sizes(site_packages_dirs):
    """Get all packages and their sizes from site-packages directories"""
    packages = {}
    for sp_dir in site_packages_dirs:
        if not os.path.exists(sp_dir):
            continue
        for item in os.listdir(sp_dir):
            item_path = os.path.join(sp_dir, item)
            if item.startswith('_') or item.endswith('.dist-info') or item.endswith('.egg-info'):
                continue
            if item.endswith('.py') or item.endswith('.pyd') or item.endswith('.so'):
                pkg_name = item.rsplit('.', 1)[0].lower()
            elif os.path.isdir(item_path):
                pkg_name = item.lower()
            else:
                continue
            # Calculate size
            total_size = 0
            if os.path.isfile(item_path):
                total_size = os.path.getsize(item_path)
            elif os.path.isdir(item_path):
                for r, d, fls in os.walk(item_path):
                    for fl in fls:
                        try:
                            total_size += os.path.getsize(os.path.join(r, fl))
                        except:
                            pass
            if pkg_name not in packages or total_size > packages[pkg_name]:
                packages[pkg_name] = total_size
    return packages

results = {}
for proj_name, proj_path in projects:
    sp_dirs = find_site_packages(proj_path)
    pkgs = get_packages_with_sizes(sp_dirs)
    results[proj_name] = {
        'site_packages_dirs': sp_dirs,
        'package_count': len(pkgs),
        'total_size_mb': round(sum(pkgs.values()) / (1024*1024), 2),
        'packages': pkgs
    }

# Step 2: Compare - find duplicates
proj_names = list(results.keys())
p1, p2 = proj_names[0], proj_names[1]
pkgs1 = results[p1]['packages']
pkgs2 = results[p2]['packages']

common = set(pkgs1.keys()) & set(pkgs2.keys())
only_p1 = set(pkgs1.keys()) - set(pkgs2.keys())
only_p2 = set(pkgs2.keys()) - set(pkgs1.keys())

# Duplicates with sizes
duplicates = []
for pkg in common:
    s1 = pkgs1[pkg]
    s2 = pkgs2[pkg]
    combined = s1 + s2
    duplicates.append({
        'package': pkg,
        f'size_in_{p1}_mb': round(s1/(1024*1024), 2),
        f'size_in_{p2}_mb': round(s2/(1024*1024), 2),
        'combined_mb': round(combined/(1024*1024), 2),
        'potential_savings_mb': round(min(s1,s2)/(1024*1024), 2)
    })

duplicates.sort(key=lambda x: x['combined_mb'], reverse=True)

# Heavy duplicates (>1 MB combined)
heavy_duplicates = [d for d in duplicates if d['combined_mb'] >= 1.0]

final = {
    'status': 'SUCCESS',
    'projects': {
        p1: {
            'path': projects[0][1],
            'site_packages_found': len(results[p1]['site_packages_dirs']),
            'total_packages': results[p1]['package_count'],
            'total_size_mb': results[p1]['total_size_mb']
        },
        p2: {
            'path': projects[1][1],
            'site_packages_found': len(results[p2]['site_packages_dirs']),
            'total_packages': results[p2]['package_count'],
            'total_size_mb': results[p2]['total_size_mb']
        }
    },
    'comparison': {
        'common_packages': len(common),
        f'only_in_{p1}': len(only_p1),
        f'only_in_{p2}': len(only_p2),
        'total_duplicates': len(duplicates),
        'heavy_duplicates_count': len(heavy_duplicates),
        'total_duplicate_waste_mb': round(sum(d['potential_savings_mb'] for d in duplicates), 2),
        'heavy_duplicate_waste_mb': round(sum(d['potential_savings_mb'] for d in heavy_duplicates), 2)
    },
    'heavy_duplicates_top30': heavy_duplicates[:30],
    'all_duplicates_count': len(duplicates)
}

# Save report
report_path = r'C:\Users\Revexn\agent_reports\package_comparison.json'
os.makedirs(os.path.dirname(report_path), exist_ok=True)
with open(report_path, 'w', encoding='utf-8') as f:
    json.dump(final, f, ensure_ascii=False, indent=2)

print(json.dumps(final, ensure_ascii=False, indent=2))
print(f'\nReport saved to: {report_path}')
